    "static boolean isSimpleNumber(String s) {
    int len = s.length();
    if (len == 0) {
      return false;
    }
    int start = 0;
    char first = s.charAt(0);
    if (first == '-') {
      if (len == 1) {
        return false; // just "-" is not a number
      }
      start = 1;
    }
    for (int index = start; index < len; index++) {
      char c = s.charAt(index);
      if (c < '0' || c > '9') {
        return false;
      }
    }
    return true;
  }"
  ]
}

